// Bilingual description builder. Each language block:
//   { text: intro paragraph, effects: [strings], comp: composition string }
function descBi(ru, kz) {
  const build = (x, labels) => `<p>${x.text}</p>
<span class="pm-section-label">${labels.action}</span>
<ul class="pm-effects">${x.effects.map(e => `<li>${e}</li>`).join('')}</ul>
<span class="pm-section-label">${labels.comp}</span>
<p class="pm-comp">${x.comp}</p>`;
  return {
    ru: build(ru, { action: 'Действие', comp: 'Состав' }),
    kz: build(kz, { action: 'Әсері',   comp: 'Құрамы' }),
  };
}

// Legacy monolingual helper — returns {ru, kz} with KZ=RU (used for filler items without translations)
function desc(text, effects, composition) {
  const html = `<p>${text}</p>
<span class="pm-section-label">Действие</span>
<ul class="pm-effects">${effects.map(e => `<li>${e}</li>`).join('')}</ul>
<span class="pm-section-label">Состав</span>
<p class="pm-comp">${composition}</p>`;
  return { ru: html, kz: html };
}

// Helper: wraps a plain string as a {ru, kz} pair (kz falls back to ru)
function bi(s) { return { ru: s, kz: s }; }

